import { Injectable, Logger } from '@nestjs/common';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import {
	IGithubContributorBase,
	IGithubContributorUpsert,
} from '@modules/github/types/github-contributor.interface';

import { TABLE_NAME_GITHUB_CONTRIBUTORS } from '@constants/db.constant';

@Injectable()
export class GithubContributorModel {
	private readonly logger = new Logger(GithubContributorModel.name);
	private readonly tableName = TABLE_NAME_GITHUB_CONTRIBUTORS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async upsert({ data }: { data: IGithubContributorUpsert }): Promise<void> {
		try {
			await this.knexWrite<IGithubContributorBase>(this.tableName)
				.insert({
					_id: randomUUID(),
					...data,
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.onConflict(['installation_id', 'github_user_id'])
				.merge(['github_login', 'github_name', 'github_email', 'updated_at']);

			this.logger.debug(
				`Upserted contributor ${data.github_login} for installation ${data.installation_id}`,
			);
		} catch (error) {
			this.logger.error(
				`Failed to upsert contributor ${data.github_login}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

