		try {
			const result = await this.knexRead<IGithubContributorBase>(this.tableName)
				.where({ installation_id: installationId, github_login: githubLogin })
				.first();

			return result ?? null;
		} catch (error) {
			this.logger.error(
				`Failed to find contributor ${githubLogin} for installation ${installationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}

import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import {
	IGithubCommitBase,
	IGithubCommitUpsert,
} from '@modules/github/types/github-commit.interface';

import { TABLE_NAME_GITHUB_COMMITS } from '@constants/db.constant';

@Injectable()
export class GithubCommitModel {
	private readonly logger = new Logger(GithubCommitModel.name);
	private readonly tableName = TABLE_NAME_GITHUB_COMMITS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async upsertMany({ commits }: { commits: IGithubCommitUpsert[] }): Promise<void> {
		if (commits.length === 0) return;

		try {
			const rows = commits.map((commit) => ({
				_id: randomUUID(),
				...commit,
				created_at: this.knexWrite.fn.now(),
				updated_at: this.knexWrite.fn.now(),
			}));

			await this.knexWrite<IGithubCommitBase>(this.tableName)
				.insert(rows)
				.onConflict(['repo_id', 'sha'])
				.merge([
					'message',
					'author_login',
					'author_name',
					'author_email',
					'additions',
					'deletions',
					'updated_at',
				]);

			this.logger.debug(`Upserted ${commits.length} commits`);
		} catch (error) {
			this.logger.error(`Failed to upsert commits: ${(error as Error).message}`);
			throw error;
		}
	}

	async findByRepoId({ repoId }: { repoId: string }): Promise<IGithubCommitBase[]> {
		try {
			return await this.knexRead<IGithubCommitBase>(this.tableName)
				.where({ repo_id: repoId })
				.orderBy('committed_at', 'desc');
		} catch (error) {
			this.logger.error(
				`Failed to find commits for repo ${repoId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}

